import org.junit.Assert.assertEquals
import org.junit.Test

class StringCompression3Test {
    @Test
    fun test1() {
        val string = "abcde"
        val expected = "1a1b1c1d1e"
        val result = StringCompression3().compressedString(string)
        assertEquals(expected, result)
    }

    @Test
    fun test2() {
        val string = "aaaaaaaaaaaabb"
        val expected = "9a3a2b"
        val result = StringCompression3().compressedString(string)
        assertEquals(expected, result)
    }

    @Test
    fun test3() {
        val string = "aabbaa"
        val expected = "2a2b2a"
        val result = StringCompression3().compressedString(string)
        assertEquals(expected, result)
    }

    @Test
    fun test4() {
        val string = "a"
        val expected = "1a"
        val result = StringCompression3().compressedString(string)
        assertEquals(expected, result)
    }

    @Test
    fun test5() {
        val string = ""
        val expected = ""
        val result = StringCompression3().compressedString(string)
        assertEquals(expected, result)
    }

    @Test
    fun test7() {
        val string = "aaaaaaaaaaaaaaaaaaabbbbbb"
        val expected = "9a9a1a6b"
        val result = StringCompression3().compressedString(string)
        assertEquals(expected, result)
    }
}